}

void insertionSort(int arr[], int n) {
    for (int i = 1; i < n; i++) {
        int key = arr[i], j = i - 1;
        while (j >= 0 && arr[j] > key) {
            arr[j+1] = arr[j];
            j--;
        }
        arr[j+1] = key;
    }
}
int main() {
    int arr[] = {5, 2, 4, 1};
    insertionSort(arr, 4);
    printf("%d %d", arr[1], arr[2]);
