int isArmstrong(int n) {
    int orig = n, sum = 0, digits = 0;
    int temp = n;
    while (temp > 0) { digits++; temp /= 10; }
    while (n > 0) {
        int d = n % 10;
        int power = 1;
        for (int i = 0; i < digits; i++) power *= d;
        sum += power;
        n /= 10;
    }
    return sum == orig;
}
