void rotateLeft(int arr[], int n, int k) {
    k = k % n;
    for (int r = 0; r < k; r++) {
        int first = arr[0];
        for (int i = 0; i < n - 1; i++)
            arr[i] = arr[i + 1];
        arr[n - 1] = first;
    }
}
int main() {
    int arr[] = {1, 2, 3, 4, 5};
    rotateLeft(arr, 5, 2);
    printf("%d %d %d", arr[0], arr[2], arr[4]);
    return 0;
}

void rotateRight(int arr[], int n, int k) {
    k = k % n;
    for (int r = 0; r < k; r++) {
        int last = arr[n - 1];
        for (int i = n - 1; i > 0; i--)
            arr[i] = arr[i - 1];
        arr[0] = last;
    }
}
int main() {
    int arr[] = {1, 2, 3, 4, 5};
    rotateRight(arr, 5, 2);
    printf("%d %d %d", arr[0], arr[2], arr[4]);
    return 0;
}

