    for (int i = 1; i < n; i++) {
        int next2 = ugly[i2] * 2;
        int next3 = ugly[i3] * 3;
        int next5 = ugly[i5] * 5;
        int next = (next2 < next3) ? ((next2 < next5) ? next2 : next5) : ((next3 < next5) ? next3 : next5);
