int searchRotated(int arr[], int n, int target) {
    int l = 0, r = n - 1;
    while (l <= r) {
        int mid = l + (r - l) / 2;
        if (arr[mid] == target) return mid;
        if (arr[l] <= arr[mid]) {
            if (arr[l] <= target && target < arr[mid]) r = mid - 1;
            else l = mid + 1;
        } else {
            if (arr[mid] < target && target <= arr[r]) l = mid + 1;
            else r = mid - 1;
        }
    }
    return -1;
}
int main() {
    int arr[] = {4, 5, 6, 7, 0, 1, 2};
    printf("%d", searchRotated(arr, 7, 0));
    return 0;
}

int findMin(int arr[], int n) {
    int l = 0, r = n - 1;
    while (l < r) {
        int mid = l + (r - l) / 2;
        if (arr[mid] > arr[r]) l = mid + 1;
        else r = mid;
    }
    return arr[l];
}
int main() {
