}

int nthRoot(int n, int x) {
    int l = 1, r = x;
    while (l <= r) {
        int mid = l + (r - l) / 2;
        long long power = 1;
        for (int i = 0; i < n; i++) power *= mid;
        if (power == x) return mid;
        if (power < x) l = mid + 1;
        else r = mid - 1;
    }
    return -1;
}
