    return 0;
}

int findFloor(int arr[], int n, int x) {
    int l = 0, r = n - 1, floor = -1;
    while (l <= r) {
        int mid = l + (r - l) / 2;
        if (arr[mid] == x) return mid;
        if (arr[mid] < x) { floor = mid; l = mid + 1; }
        else r = mid - 1;
    }
    return floor;
}
