int matrixSearch(int matrix[][4], int rows, int cols, int target) {
    int l = 0, r = rows * cols - 1;
    while (l <= r) {
        int mid = l + (r - l) / 2;
        int val = matrix[mid / cols][mid % cols];
        if (val == target) return 1;
        if (val < target) l = mid + 1;
        else r = mid - 1;
    }
    return 0;
}
