}

int interpolationSearch(int arr[], int n, int x) {
    int l = 0, r = n - 1;
    while (l <= r && x >= arr[l] && x <= arr[r]) {
        int pos = l + ((x - arr[l]) * (r - l)) / (arr[r] - arr[l]);
        if (arr[pos] == x) return pos;
        if (arr[pos] < x) l = pos + 1;
        else r = pos - 1;
    }
    return -1;
}
