}

int ternarySearch(int arr[], int l, int r, int x) {
    if (r >= l) {
        int mid1 = l + (r - l) / 3;
        int mid2 = r - (r - l) / 3;
        if (arr[mid1] == x) return mid1;
        if (arr[mid2] == x) return mid2;
        if (x < arr[mid1]) return ternarySearch(arr, l, mid1 - 1, x);
        if (x > arr[mid2]) return ternarySearch(arr, mid2 + 1, r, x);
        return ternarySearch(arr, mid1 + 1, mid2 - 1, x);
    }
    return -1;
}
int main() {
    int arr[] = {1, 2, 3, 4, 5, 6, 7, 8, 9};
    printf("%d", ternarySearch(arr, 0, 8, 5));
    return 0;
}

int jumpSearch(int arr[], int n, int x) {
    int step = (int)sqrt(n);
    int prev = 0;
    while (arr[(step < n ? step : n) - 1] < x) {
        prev = step;
        step += (int)sqrt(n);
        if (prev >= n) return -1;
    }
    while (arr[prev] < x) {
        prev++;
        if (prev == (step < n ? step : n)) return -1;
    }
    return (arr[prev] == x) ? prev : -1;
}
