int slidingWindowMax(int arr[], int n, int k) {
    int max = arr[0];
    for (int i = 0; i < k; i++) if (arr[i] > max) max = arr[i];
    int result = max;
    for (int i = k; i < n; i++) {
        max = arr[i-k+1];
        for (int j = i-k+1; j <= i; j++) if (arr[j] > max) max = arr[j];
        if (max > result) result = max;
    }
    return result;
}
