int longestValidParentheses(char *s) {
    int maxLen = 0, left = 0, right = 0;
    for (int i = 0; s[i]; i++) {
        if (s[i] == '(') left++;
        else right++;
        if (left == right) {
            if (2 * right > maxLen) maxLen = 2 * right;
        } else if (right > left) {
            left = right = 0;
        }
    }
    left = right = 0;
    for (int i = 0; s[i]; i++);
    for (int i = i - 1; i >= 0; i--) {
        if (s[i] == ')') right++;
        else left++;
        if (left == right) {
            if (2 * left > maxLen) maxLen = 2 * left;
        } else if (left > right) {
            left = right = 0;
        }
    }
    return maxLen;
}
