int evaluatePostfix(char *exp) {
    int stack[100], top = -1;
    for (int i = 0; exp[i]; i++) {
        if (exp[i] >= '0' && exp[i] <= '9')
            stack[++top] = exp[i] - '0';
        else {
            int b = stack[top--], a = stack[top--];
            switch(exp[i]) {
                case '+': stack[++top] = a + b; break;
                case '-': stack[++top] = a - b; break;
                case '*': stack[++top] = a * b; break;
                case '/': stack[++top] = a / b; break;
            }
        }
    }
    return stack[top];
}
