int editDistance(char *s1, char *s2) {
    int m = 0, n = 0;
    while (s1[m]) m++;
    while (s2[n]) n++;
    int dp[m+1][n+1];
    for (int i = 0; i <= m; i++) dp[i][0] = i;
    for (int j = 0; j <= n; j++) dp[0][j] = j;
    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (s1[i-1] == s2[j-1]) dp[i][j] = dp[i-1][j-1];
            else {
                int ins = dp[i][j-1], del = dp[i-1][j], rep = dp[i-1][j-1];
                dp[i][j] = 1 + (ins < del ? (ins < rep ? ins : rep) : (del < rep ? del : rep));
            }
        }
    }
    return dp[m][n];
}
int main() {
    printf("%d", editDistance("horse", "ros"));
    return 0;
}

int lcs(char *s1, char *s2) {
