    printf("%d", longestPalindromicSubseq("bbbab"));
    return 0;
}

int knapsack01(int wt[], int val[], int n, int W) {
    int dp[n+1][W+1];
    for (int i = 0; i <= n; i++) {
        for (int w = 0; w <= W; w++) {
            if (i == 0 || w == 0) dp[i][w] = 0;
            else if (wt[i-1] <= w)
                dp[i][w] = val[i-1] + dp[i-1][w-wt[i-1]] > dp[i-1][w] ?
                           val[i-1] + dp[i-1][w-wt[i-1]] : dp[i-1][w];
            else dp[i][w] = dp[i-1][w];
        }
    }
    return dp[n][W];
}
int main() {
    int wt[] = {10, 20, 30}, val[] = {60, 100, 120};
    printf("%d", knapsack01(wt, val, 3, 50));
    return 0;
}

int unboundedKnapsack(int wt[], int val[], int n, int W) {
    int dp[W+1];
    for (int i = 0; i <= W; i++) dp[i] = 0;
    for (int w = 1; w <= W; w++) {
        for (int i = 0; i < n; i++) {
            if (wt[i] <= w && dp[w - wt[i]] + val[i] > dp[w])
                dp[w] = dp[w - wt[i]] + val[i];
        }
    }
    return dp[W];
}
