int wordBreak(char *s, char *dict[], int dictSize) {
    int n = 0;
    while (s[n]) n++;
    int dp[n+1];
    dp[0] = 1;
    for (int i = 1; i <= n; i++) {
        dp[i] = 0;
        for (int j = 0; j < i; j++) {
            if (dp[j]) {
                for (int k = 0; k < dictSize; k++) {
                    int len = 0;
                    while (dict[k][len]) len++;
                    if (len == i - j) {
                        int match = 1;
                        for (int m = 0; m < len; m++)
                            if (s[j+m] != dict[k][m]) { match = 0; break; }
                        if (match) { dp[i] = 1; break; }
                    }
                }
            }
            if (dp[i]) break;
        }
    }
    return dp[n];
}
int main() {
