    printf("%d", wordBreak("leetcode", dict, 2));
    return 0;
}

int decodeWays(char *s) {
    int n = 0;
    while (s[n]) n++;
    if (n == 0 || s[0] == '0') return 0;
    int dp[n+1];
    dp[0] = 1; dp[1] = 1;
    for (int i = 2; i <= n; i++) {
        dp[i] = 0;
        if (s[i-1] != '0') dp[i] = dp[i-1];
        int twoDigit = (s[i-2] - '0') * 10 + (s[i-1] - '0');
        if (twoDigit >= 10 && twoDigit <= 26) dp[i] += dp[i-2];
    }
    return dp[n];
}
