    for (int i = 2; i <= n; i++) {
        dp[i] = 0;
        for (int j = 1; j < i; j++) {
            int product = j * (i - j > dp[i-j] ? i - j : dp[i-j]);
            if (product > dp[i]) dp[i] = product;
        }
    }
    return dp[n];
}
