    int n2 = r - m;
    int L[n1], R[n2];
    for (i = 0; i < n1; i++) L[i] = arr[l + i];
    for (j = 0; j < n2; j++) R[j] = arr[m + 1 + j];
    i = 0; j = 0; k = l;
    while (i < n1 && j < n2)
        arr[k++] = (L[i] <= R[j]) ? L[i++] : R[j++];
    while (i < n1) arr[k++] = L[i++];
    while (j < n2) arr[k++] = R[j++];
}
int main() {
    printf("Merge function defined");
    return 0;
}

int partition(int arr[], int l, int h) {
    int p = arr[h];
    int i = l - 1;
    for (int j = l; j < h; j++)
        if (arr[j] < p) { i++; int t = arr[i]; arr[i] = arr[j]; arr[j] = t; }
    int t = arr[i+1]; arr[i+1] = arr[h]; arr[h] = t;
    return i + 1;
}
int main() {
    printf("Partition function defined");
    return 0;
}

void selectionSort(int arr[], int n, int i) {
    if (i >= n - 1) return;
    int min = i;
    for (int j = i + 1; j < n; j++)
        if (arr[j] < arr[min]) min = j;
    int t = arr[i]; arr[i] = arr[min]; arr[min] = t;
    selectionSort(arr, n, i + 1);
}
int main() {
    int arr[] = {3, 1, 2};
    selectionSort(arr, 3, 0);
    printf("%d %d %d", arr[0], arr[1], arr[2]);
    return 0;
}

void insertSort(int arr[], int n) {
    if (n <= 1) return;
    insertSort(arr, n - 1);
    int last = arr[n-1];
    int j = n - 2;
    while (j >= 0 && arr[j] > last) {
        arr[j+1] = arr[j];
        j--;
    }
    arr[j+1] = last;
}
int main() {
    int arr[] = {3, 1, 2};
    insertSort(arr, 3);
    printf("%d %d %d", arr[0], arr[1], arr[2]);
    return 0;
}

